INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '9be18cde-01b2-49f4-a272-52a5fbc28138',
  '00000000-0000-0000-0000-000000000001',
  $escape$FastAPI Middleware — Pipeline Order, Global vs Route-Specific$escape$,
  $escape$FastAPI middleware wraps every request/response cycle via `app.add_middleware()`. Execution order is LIFO — the last middleware added runs first on the way in, last on the way out. This means if you add logging, then CORS, then GZip, GZip processes the request first. Global middleware added via `add_middleware()` fires on every route including static files and mounted sub-apps. For route-specific logic, prefer dependencies with `Depends()` instead — they respect router scope and won't pollute unrelated endpoints. Use `BaseHTTPMiddleware` for simple cases, but be aware it buffers the full response body, which breaks streaming. For streaming compatibility, implement the ASGI middleware interface directly using `__call__(scope, receive, send)`. Starlette's `add_middleware()` also accepts any pure ASGI middleware class, not just `BaseHTTPMiddleware` subclasses. A common mistake: placing `add_cors_middleware()` after `add_gzip_middleware()` — CORS headers get compressed before the browser reads them.$escape$,
  $escape$from fastapi import FastAPI, Request
from starlette.middleware.base import BaseHTTPMiddleware
import time

app = FastAPI()

class TimingMiddleware(BaseHTTPMiddleware):
    async def dispatch(self, request: Request, call_next):
        start = time.perf_counter()
        response = await call_next(request)
        duration = time.perf_counter() - start
        response.headers["X-Process-Time"] = str(duration)
        return response

# Added last = runs first on ingress
app.add_middleware(TimingMiddleware)
# CORS must be added AFTER timing so it wraps outermost
from starlette.middleware.cors import CORSMiddleware
app.add_middleware(CORSMiddleware, allow_origins=["*"])$escape$,
