INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '10fdb5c5-0818-4401-8bed-a2edc1239c16',
  '00000000-0000-0000-0000-000000000001',
  $escape$FastAPI Project Structure — MVC Is a Trap, Use Vertical Slices$escape$,
  $escape$Most FastAPI tutorials push you toward an MVC-style layout: a top-level `routers/`, `models/`, `schemas/`, `services/` split. It looks tidy until your app grows — then changing one feature means touching four directories. Vertical slice architecture groups everything by domain instead. A `features/users/` folder holds its own `router.py`, `schemas.py`, `service.py`, and `models.py`. Your `main.py` simply includes each feature's `APIRouter` via `app.include_router(users.router, prefix='/users', tags=['users'])`. FastAPI's `APIRouter` is purpose-built for this: it supports prefix, tags, dependencies, and response models at the router level, so each slice is fully self-contained. Shared infrastructure — `db.py`, `auth.py`, `exceptions.py` — lives in a top-level `core/` module, imported by slices as needed. This maps directly to FastAPI's Dependency Injection system: slice-level `Depends()` chains stay local, cross-cutting concerns (e.g. `get_current_user`) live in `core/deps.py`. When a slice grows large enough, it becomes a mounted sub-application via `app.mount()` with zero refactoring.$escape$,
  $escape$# app/features/users/router.py
from fastapi import APIRouter, Depends
from app.core.deps import get_current_user
from .schemas import UserOut
from .service import UserService

router = APIRouter()

@router.get('/me', response_model=UserOut)
async def get_me(
    current_user=Depends(get_current_user),
    svc: UserService = Depends()
):
    return await svc.get_by_id(current_user.id)

# app/main.py
from app.features.users.router import router as users_router
app.include_router(users_router, prefix='/users', tags=['users'])$escape$,
  $escape$python$escape$,
