INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'bb6b69ae-e342-43dd-b7a1-8b01a407cdf3',
  '00000000-0000-0000-0000-000000000001',
  $escape$FastAPI Input Validation — Schema Enforcement, Sanitization, and Error Responses$escape$,
  $escape$FastAPI uses Pydantic v2 models as the validation layer at every boundary — request bodies, query params, path params, and headers. Define a `BaseModel` subclass and FastAPI automatically parses, coerces, and validates before your handler runs. For stricter constraints, use `Annotated` with `Field()`: set `min_length`, `max_length`, `pattern` (regex), `ge`/`le` for numerics. For sanitization, add a `@field_validator` with `mode='before'` to strip whitespace or normalize input before type coercion. When validation fails, FastAPI returns a `422 Unprocessable Entity` with a structured `detail` list — each entry identifies the failing field, location, and error type. You can override this entirely by catching `RequestValidationError` via `app.exception_handler(RequestValidationError)` and returning a custom `JSONResponse`. For query params, annotate directly in the function signature using `Query(min_length=1, max_length=50)` — Pydantic's machinery handles it identically to body models. Never trust raw input; always declare constraints at the schema level, not inside handler logic.$escape$,
  $escape$from fastapi import FastAPI, Query
from fastapi.exceptions import RequestValidationError
from fastapi.responses import JSONResponse
from pydantic import BaseModel, Field, field_validator
from typing import Annotated

app = FastAPI()

class CreateUserRequest(BaseModel):
    username: Annotated[str, Field(min_length=3, max_length=30, pattern=r'^[a-z0-9_]+$')]
    email: Annotated[str, Field(max_length=255)]

    @field_validator('username', mode='before')
    @classmethod
    def normalize(cls, v: str) -> str:
        return v.strip().lower()

@app.exception_handler(RequestValidationError)
async def validation_error_handler(request, exc: RequestValidationError):
    return JSONResponse(status_code=400, content={"errors": exc.errors()})

@app.post("/users")
async def create_user(body: CreateUserRequest, q: Annotated[str | None, Query(max_length=50)] = None):
    return {"username": body.username}$escape$,
  $escape$python$escape$,
