INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '0f44a0c2-096a-45ad-ba82-9e89e52db9e8',
  '00000000-0000-0000-0000-000000000001',
  $escape$FastAPI JWT Auth — Dependency Injection for Clean Middleware Patterns$escape$,
  $escape$FastAPI's dependency injection system is the idiomatic way to handle JWT validation — not middleware. Use `Depends()` to declare auth requirements per route, keeping concerns separated and testable. Define a `get_current_user` dependency that pulls the `Authorization` header via `HTTPBearer`, decodes the JWT with `python-jose`, and raises `HTTPException(401)` on failure. Inject it into routes with `Depends(get_current_user)`. For session handling, FastAPI has no built-in session layer — pair it with `itsdangerous` or `starsessions` for server-side sessions, or stay stateless with JWT refresh tokens. If you genuinely need global auth logic (e.g., rate limiting by user), use `app.middleware('http')` or a `BaseHTTPMiddleware` subclass, but note these can't use `Depends()` — extract shared logic into plain functions instead. For role-based access, chain dependencies: `Depends(require_role('admin'))` calls `get_current_user` internally. This composes cleanly, documents itself in the OpenAPI schema, and lets you mock auth trivially in tests using `app.dependency_overrides`.$escape$,
  $escape$from fastapi import Depends, HTTPException, status
from fastapi.security import HTTPBearer, HTTPAuthorizationCredentials
from jose import JWTError, jwt

bearer = HTTPBearer()
SECRET, ALGORITHM = "secret", "HS256"

def get_current_user(creds: HTTPAuthorizationCredentials = Depends(bearer)):
    try:
        payload = jwt.decode(creds.credentials, SECRET, algorithms=[ALGORITHM])
        return payload["sub"]
    except JWTError:
        raise HTTPException(status_code=status.HTTP_401_UNAUTHORIZED, detail="Invalid token")

@app.get("/me")
def me(user_id: str = Depends(get_current_user)):
    return {"user": user_id}$escape$,
  $escape$python$escape$,
