INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'c1c2ded4-2bd0-463a-8f69-100b68bfe3a3',
  '00000000-0000-0000-0000-000000000001',
  $escape$FastAPI Testing — Unit vs Integration, Mocking HTTP, and Test DB Strategy$escape$,
  $escape$FastAPI's `TestClient` (built on `httpx`) blurs the unit/integration line — use it for integration tests that exercise your full request/response cycle including middleware and dependency injection. For pure unit tests, test business logic functions directly without spinning up the app. Mock external HTTP calls using `respx` (httpx-native) rather than `unittest.mock`, since FastAPI's async client uses httpx under the hood. For test databases, override the `get_db` dependency via `app.dependency_overrides` to inject a SQLite or isolated PostgreSQL session — never mutate your real DB fixture. Use `pytest` fixtures with `scope="function"` for DB teardown between tests. Pair `AsyncClient` with `pytest-asyncio` for async route testing. Avoid `TestClient` for async endpoints in production-like scenarios — it runs a sync wrapper that can mask event loop issues. Keep your `conftest.py` lean: one `engine` fixture, one `session` fixture, one `client` fixture that wires them together via `dependency_overrides`.$escape$,
  $escape$import pytest
from httpx import AsyncClient, ASGITransport
from sqlalchemy.ext.asyncio import create_async_engine, AsyncSession
from sqlalchemy.orm import sessionmaker
from app.main import app
from app.database import get_db

TEST_DB_URL = "sqlite+aiosqlite:///:memory:"
engine = create_async_engine(TEST_DB_URL)
TestingSession = sessionmaker(engine, class_=AsyncSession, expire_on_commit=False)

@pytest.fixture
async def client():
    async def override_get_db():
        async with TestingSession() as session:
            yield session
    app.dependency_overrides[get_db] = override_get_db
    async with AsyncClient(transport=ASGITransport(app=app), base_url="http://test") as ac:
        yield ac
    app.dependency_overrides.clear()$escape$,
  $escape$python$escape$,
