INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'ef56d6e1-379a-4283-a15d-bc7ede6505c5',
  '00000000-0000-0000-0000-000000000001',
  $escape$FastAPI Security — CORS, Rate Limiting, Headers, and Injection Defense$escape$,
  $escape$FastAPI's `CORSMiddleware` handles origin whitelisting, but misconfiguring `allow_origins=["*"]` with `allow_credentials=True` is a spec violation and silently breaks in browsers — use explicit origins instead. For rate limiting, `slowapi` integrates cleanly via a `Limiter` attached to `app.state`, with `@limiter.limit("10/minute")` on individual routes. Security headers (X-Content-Type-Options, X-Frame-Options, HSTS) aren't built-in — add them via a custom `BaseHTTPMiddleware` or use `secure` library's `SecureHeaders` class. For SQL injection, FastAPI's SQLAlchemy integration with parameterized queries via `text()` + bound params is safe, but raw f-string queries into `db.execute()` are not — always use `:param` syntax. For NoSQL/Redis injection, sanitize keys before use. Pydantic models at request boundaries are your best injection defense: strict typing rejects malformed payloads before they reach business logic. Enable `model_config = ConfigDict(strict=True)` on sensitive schemas to disallow type coercion.$escape$,
  $escape$from fastapi import FastAPI, Request
from fastapi.middleware.cors import CORSMiddleware
from slowapi import Limiter, _rate_limit_exceeded_handler
from slowapi.util import get_remote_address
from slowapi.errors import RateLimitExceeded
from starlette.middleware.base import BaseHTTPMiddleware
from starlette.responses import Response

limiter = Limiter(key_func=get_remote_address)
app = FastAPI()
app.state.limiter = limiter
app.add_exception_handler(RateLimitExceeded, _rate_limit_exceeded_handler)

app.add_middleware(
    CORSMiddleware,
    allow_origins=["https://app.yourdomain.com"],
    allow_credentials=True,
    allow_methods=["GET", "POST"],
    allow_headers=["Authorization", "Content-Type"],
)

class SecurityHeadersMiddleware(BaseHTTPMiddleware):
    async def dispatch(self, request: Request, call_next):
        response: Response = await call_next(request)
        response.headers["X-Content-Type-Options"] = "nosniff"
        response.headers["X-Frame-Options"] = "DENY"
        response.headers["Strict-Transport-Security"] = "max-age=63072000; includeSubDomains"
        return response

app.add_middleware(SecurityHeadersMiddleware)

@app.get("/items")
@limiter.limit("10/minute")
async def list_items(request: Request):
    return {"items": []}$escape$,
  $escape$python$escape$,
