INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'd3ea1479-93d7-46bd-8b0a-b681e54e0743',
  '00000000-0000-0000-0000-000000000001',
  $escape$FastAPI Settings Management with pydantic-settings$escape$,
  $escape$FastAPI pairs naturally with `pydantic-settings` for type-safe configuration. Define a `Settings` class inheriting from `BaseSettings` — Pydantic automatically reads values from environment variables, `.env` files, and secrets directories, with full type coercion and validation.

Use `@lru_cache` on your `get_settings()` dependency so the settings object is instantiated once per process, not on every request. Inject it via `Depends(get_settings)` in your route handlers.

For secrets, set `model_config = SettingsConfigDict(secrets_dir='/run/secrets')` — Pydantic reads files in that directory as field values, ideal for Docker secrets or Kubernetes mounted secrets. Field names map directly to filenames.

Never instantiate `Settings()` at module level outside the cached factory — doing so breaks environment override in tests. Instead, always go through `get_settings()`. In tests, override the dependency with `app.dependency_overrides[get_settings] = lambda: Settings(database_url='sqlite://:memory:')` for clean isolation without monkeypatching `os.environ`.$escape$,
  $escape$from functools import lru_cache
from pydantic import SecretStr
from pydantic_settings import BaseSettings, SettingsConfigDict

class Settings(BaseSettings):
    model_config = SettingsConfigDict(
        env_file=".env", secrets_dir="/run/secrets", env_file_encoding="utf-8"
    )
    database_url: str
    api_key: SecretStr
    debug: bool = False

@lru_cache
def get_settings() -> Settings:
    return Settings()

# In your route:
# @app.get("/")
# def root(settings: Settings = Depends(get_settings)): ...$escape$,
  $escape$python$escape$,
