INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '583425ed-92ce-406c-81c8-d0ac2258f5d7',
  '00000000-0000-0000-0000-000000000001',
  $escape$FastAPI Serialization — DTOs, camelCase, and Null Handling Done Right$escape$,
  $escape$FastAPI uses Pydantic models as your request/response DTOs. By default, field names serialize as-is (snake_case), but most frontend clients expect camelCase. Use `model_config = ConfigDict(alias_generator=to_camel, populate_by_name=True)` on your Pydantic model to handle this automatically — `populate_by_name=True` lets FastAPI still accept snake_case on inbound requests. For response serialization, pass `by_alias=True` to `response_model_by_alias=True` on your route decorator so the alias is used in the JSON output. For null handling, Pydantic v2 distinguishes between a field being absent and explicitly `None`. Use `Optional[str] = None` for nullable fields, but if you want to exclude unset fields from responses entirely, call `.model_dump(exclude_unset=True)` before returning. Pair this with `response_model_exclude_none=True` on the route to strip null fields from the serialized response automatically — useful for sparse update payloads and keeping API responses clean without manual filtering.$escape$,
  $escape$from pydantic import BaseModel, ConfigDict
from pydantic.alias_generators import to_camel
from fastapi import FastAPI

app = FastAPI()

class UserResponse(BaseModel):
    model_config = ConfigDict(alias_generator=to_camel, populate_by_name=True)

    user_id: int
    display_name: str
    bio: str | None = None

@app.get("/users/{user_id}", response_model=UserResponse, response_model_by_alias=True, response_model_exclude_none=True)
async def get_user(user_id: int) -> UserResponse:
    return UserResponse(user_id=user_id, display_name="sravan", bio=None)$escape$,
  $escape$python$escape$,
