INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '709ef62d-e562-469a-998f-6ecf1b30ed14',
  '00000000-0000-0000-0000-000000000001',
  $escape$FastAPI Monitoring — Health Checks, Prometheus Metrics, and OpenTelemetry Tracing$escape$,
  $escape$FastAPI pairs naturally with three monitoring layers. For health checks, define a `/health` route returning dependency statuses — database ping, Redis connectivity, external API reachability — not just `{"status": "ok"}`. Use `prometheus-fastapi-instrumentator` to expose `/metrics` with zero boilerplate: one `Instrumentator().instrument(app).expose(app)` call gives you request count, latency histograms, and in-flight gauges per route automatically. For distributed tracing, `opentelemetry-instrumentation-fastapi` auto-instruments every request, propagating W3C `traceparent` headers across service boundaries. Configure an OTLP exporter to send spans to Jaeger, Tempo, or any OpenTelemetry-compatible backend. The key integration point is FastAPI's `lifespan` context — initialize your `TracerProvider` and flush it on shutdown there, not in a plain `@app.on_event` (deprecated). Combine all three layers: health for alerting, metrics for dashboards, traces for root-cause analysis. Route `/health` and `/metrics` to a separate internal port using `uvicorn`'s `--port` alongside a secondary `Server` instance to avoid exposing them publicly.$escape$,
  $escape$from fastapi import FastAPI
from contextlib import asynccontextmanager
from prometheus_fastapi_instrumentator import Instrumentator
from opentelemetry import trace
from opentelemetry.sdk.trace import TracerProvider
from opentelemetry.sdk.trace.export import BatchSpanProcessor
from opentelemetry.exporter.otlp.proto.grpc.trace_exporter import OTLPSpanExporter
from opentelemetry.instrumentation.fastapi import FastAPIInstrumentor

@asynccontextmanager
async def lifespan(app: FastAPI):
    provider = TracerProvider()
    provider.add_span_processor(BatchSpanProcessor(OTLPSpanExporter(endpoint="http://otel-collector:4317")))
    trace.set_tracer_provider(provider)
    FastAPIInstrumentor.instrument_app(app)
    yield
    provider.shutdown()

app = FastAPI(lifespan=lifespan)
Instrumentator().instrument(app).expose(app)

@app.get("/health")
async def health(db: AsyncSession = Depends(get_db)):
    await db.execute(text("SELECT 1"))
    return {"status": "healthy", "db": "ok"}$escape$,
