INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'cd1822b8-d05d-4e13-970a-1305a75b2319',
  '00000000-0000-0000-0000-000000000001',
  $escape$FastAPI Dev Tooling — Hot Reload, CLI Scaffolding, and Code Generation$escape$,
  $escape$FastAPI's development loop centers on Uvicorn's `--reload` flag, but most developers don't configure it beyond the default. Pass `--reload-dir` to watch only your app package, not the entire working directory — this prevents reloads triggered by log files or migration artifacts. Pair it with `--reload-delay 0.1` to debounce rapid saves.

For scaffolding, `fastapi-cli` (shipped with FastAPI 0.111+) provides `fastapi dev` and `fastapi run` commands that wrap Uvicorn with sensible defaults: `fastapi dev main.py` enables reload automatically and binds to `127.0.0.1` only, while `fastapi run` targets production with `0.0.0.0`.

For code generation, `datamodel-code-generator` converts OpenAPI schemas or JSON Schema directly into Pydantic v2 models — critical when integrating third-party APIs. Run it as a pre-commit step or Makefile target to keep models in sync with upstream specs. Combine with `openapi-python-client` to auto-generate a fully typed async client from your own FastAPI app's `/openapi.json` endpoint.$escape$,
  $escape$# Install
# pip install fastapi[standard] datamodel-code-generator openapi-python-client

# Hot reload — watch only app dir, debounce saves
uvicorn app.main:app --reload --reload-dir app --reload-delay 0.1

# fastapi-cli equivalent (FastAPI 0.111+)
fastapi dev app/main.py

# Generate Pydantic v2 models from a remote OpenAPI spec
datamodel-codegen \
  --url https://api.example.com/openapi.json \
  --input-file-type openapi \
  --output models/external.py \
  --output-model-type pydantic_v2.BaseModel

# Generate a typed async client from your own app
openapi-python-client generate --url http://localhost:8000/openapi.json$escape$,
  $escape$bash$escape$,
